import{_ as t,c as n,a1 as a,o as s}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"SNMP Enumeration using snmp_enum","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/3-enumeration/2-SNMP-Enumeration.md","filePath":"categories/ethical-hacking-labs/3-enumeration/2-SNMP-Enumeration.md"}'),i={name:"categories/ethical-hacking-labs/3-enumeration/2-SNMP-Enumeration.md"};function o(r,e,l,p,m,c){return s(),n("div",null,e[0]||(e[0]=[a(`<h1 id="snmp-enumeration-using-snmp-enum" tabindex="-1">SNMP Enumeration using <code>snmp_enum</code> <a class="header-anchor" href="#snmp-enumeration-using-snmp-enum" aria-label="Permalink to &quot;SNMP Enumeration using \`snmp_enum\`&quot;">​</a></h1><p><strong>snmp_enum</strong> module in Metasploit allows enumeration of any devices with SNMP protocol support. It supports hardware, software, and network information. The default community used is &#39;public&#39;.</p><p>SNMP enumeration is the process of enumerating the users accounts and devices on a SNMP enabled computer.</p><p>SNMP service comes with two passwords, which are used to configure and access the SNMP agent from the management station. They are: Read community string and Read/Write community string. These strings (passwords) come with a default value, which is same for all the systems. They become easy entry points for attackers if left unchanged by administrator.</p><p>Attackers enumerate SNMP to extract information about network resources such as hosts, routers, devices, shares(...) Network information such as ARP tables, routing tables, device specific information and traffic statistics.</p><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><p>Enumeration:</p><ul><li>Connected devices</li><li>Hostname and information</li><li>Domain</li><li>Hardware and storage information</li><li>Software components</li><li>Total memory</li></ul><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Kali Linux machine (Attacker)</li><li>Windows Server 2012 / 2016 (Victim/Target)</li><li>Ubuntu <a href="https://www.vulnhub.com/entry/bwapp-bee-box-v16,53/" target="_blank" rel="noreferrer">BeeBox</a> (Victim/Target)</li></ul><h2 id="test-for-snmp-port-status" tabindex="-1">Test for SNMP Port Status <a class="header-anchor" href="#test-for-snmp-port-status" aria-label="Permalink to &quot;Test for SNMP Port Status&quot;">​</a></h2><p>First we need to find out whether the SNMP port is opened. <strong>SNMP uses port 161 by default</strong>. To check this information, we first need to run Nmap port scan.</p><p><strong>Note</strong>: Remember to activate the SNMP service on your Windows Server.</p><p><code>-sU</code>: Scans UDP port. <code>-p</code>: Port scan range.</p><p><code>nmap -sU -p 161 &lt;Target IP Address&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.38</span></span>
<span class="line"><span>Host is up (0.00070s latency).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PORT    STATE SERVICE</span></span>
<span class="line"><span>161/udp open  snmp</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span></code></pre></div><h2 id="enumerate-community-string" tabindex="-1">Enumerate Community String <a class="header-anchor" href="#enumerate-community-string" aria-label="Permalink to &quot;Enumerate Community String&quot;">​</a></h2><p>To perform SNMP enumeration, you have many tools available. This tutorial demonstrate two ways to do the same thing: using <strong>Metasploit</strong> and <strong>snmp-check</strong>.</p><p>On Metasploit, you can use <strong>snmp_enum</strong> module:</p><p><code>auxiliary/scanner/snmp/snmp_enum</code></p><p>The other way to do this is to use snmp-check. snmp-check is a package built-in on Kali Linux, just open the terminal and type:</p><p><code>snmp-check &lt;Target IP Address&gt;</code></p><p>Both methods enumerates the target machine information, and retrieve the same <strong>comprehensive list</strong> displaying the <strong>System Information</strong>. These tools supports the following enumerations:</p><ul><li>Host IP</li><li>Hostname</li><li>Hardware description</li><li>System uptime</li><li>SNMP uptime</li><li>Domain if system is connected in Domain</li><li>User Accounts</li><li>MAC Addresses</li><li>Running Processes</li><li><a href="https://tools.kali.org/information-gathering/snmp-check" target="_blank" rel="noreferrer">Etc</a></li></ul>`,24)]))}const h=t(i,[["render",o]]);export{d as __pageData,h as default};
